#!/usr/bin/env bash
# Update the Homebrew tap with the source+bun formula.
#
# The primary `ax-code` formula ships the repository source archive and
# delegates execution to the bun runtime (depends_on "bun"). Run this script
# manually after the GitHub release tag is pushed.
#
# Inputs (env):
#   GITHUB_REF_NAME — release tag (e.g. v5.5.0)
#   GH_TOKEN        — read access to the ax-code repo (for gh auth setup-git)
#   TAP_TOKEN       — write access to the Homebrew tap repo (falls back to GH_TOKEN)
set -euo pipefail

VERSION="${GITHUB_REF_NAME#v}"
TAG="v${VERSION}"
SOURCE_REPO="${GITHUB_REPOSITORY:-defai-digital/ax-code}"
RELEASE_READ_TOKEN="${GH_TOKEN:-}"
TAP_AUTH_TOKEN="${TAP_TOKEN:-${GH_TOKEN:-}}"

if [ -z "${RELEASE_READ_TOKEN}" ]; then
  echo "::error::GH_TOKEN is required"
  exit 1
fi
if [ -z "${TAP_AUTH_TOKEN}" ]; then
  echo "::error::TAP_TOKEN or GH_TOKEN is required to update the Homebrew tap"
  exit 1
fi
# Use the source-repo token for the archive download. Switch to the tap write
# token only after the download is complete so a tap-scoped token cannot
# accidentally be used to read from a private source repo.
export GH_TOKEN="${RELEASE_READ_TOKEN}"

sha256_file() {
  if command -v sha256sum >/dev/null 2>&1; then
    sha256sum "$1" | cut -d' ' -f1
  else
    shasum -a 256 "$1" | cut -d' ' -f1
  fi
}

ARCHIVE_URL="https://github.com/${SOURCE_REPO}/archive/refs/tags/${TAG}.tar.gz"
ARCHIVE_DEST="/tmp/ax-code-${VERSION}.tar.gz"

echo "Downloading source archive: ${ARCHIVE_URL}"
curl -fsSL "${ARCHIVE_URL}" -o "${ARCHIVE_DEST}"
ARCHIVE_SHA256="$(sha256_file "${ARCHIVE_DEST}")"
echo "sha256: ${ARCHIVE_SHA256}"

cat > /tmp/ax-code.rb << FORMULA
# typed: false
# frozen_string_literal: true

# Auto-generated by ax-code release tooling — do not edit manually.
class AxCode < Formula
  desc "Sovereign AI coding agent — provider-agnostic, LSP-first"
  homepage "https://github.com/defai-digital/ax-code"
  url "https://github.com/defai-digital/ax-code/archive/refs/tags/${TAG}.tar.gz"
  sha256 "${ARCHIVE_SHA256}"
  version "${VERSION}"
  license "MIT"

  depends_on "bun"
  depends_on "ripgrep"

  def install
    libexec.install Dir["*"]

    # Install workspace dependencies so @ax-code/* packages resolve correctly.
    system Formula["bun"].opt_bin/"bun", "install", "--cwd", libexec, "--ignore-scripts", "--frozen-lockfile"

    cwd = "\#{libexec}/packages/ax-code"
    entry = "\#{libexec}/packages/ax-code/src/index.ts"

    (bin/"ax-code").write <<~SH
      #!/bin/sh
      AX_CODE_ORIGINAL_CWD="\$(pwd)" exec "\#{Formula["bun"].opt_bin}/bun" run --cwd "\#{cwd}" --conditions=browser "\#{entry}" "\$@"
    SH
    chmod 0755, bin/"ax-code"
  end

  test do
    assert_match version.to_s, shell_output("\#{bin}/ax-code --version")
  end
end
FORMULA

echo "Generated formula:"
cat /tmp/ax-code.rb

TAP_DIR="$(mktemp -d)"
trap 'rm -rf "${TAP_DIR}"' EXIT
export GH_TOKEN="${TAP_AUTH_TOKEN}"
gh auth setup-git
gh repo clone defai-digital/homebrew-ax-code "${TAP_DIR}" -- --depth 1
cp /tmp/ax-code.rb "${TAP_DIR}/ax-code.rb"
cd "${TAP_DIR}"
git config user.name "github-actions[bot]"
git config user.email "github-actions[bot]@users.noreply.github.com"
git add ax-code.rb
if ! git diff --cached --quiet; then
  git commit -m "Update ax-code to v${VERSION}"
  git push
  echo "Homebrew tap updated to v${VERSION}"
else
  echo "Formula unchanged, skipping push"
fi
